import { 
  doc, getDoc, setDoc, updateDoc, onSnapshot, collection, getDocs, query, where, orderBy, deleteDoc 
} from 'firebase/firestore';
import { signInWithEmailAndPassword, signOut, createUserWithEmailAndPassword } from 'firebase/auth';
import { secondaryAuth, db, auth } from './config';



// ─── AUTH ───────────────────────────────────────────────────────────────────
export const loginPlayer = (email, password) => signInWithEmailAndPassword(auth, email, password);
export const logoutPlayer = () => signOut(auth);

// ─── PLAYERS ────────────────────────────────────────────────────────────────
export const getPlayers = async () => {
  const q = query(collection(db, 'players'));
  const snap = await getDocs(q);
  return snap.docs.map(d => ({ id: d.id, ...d.data() }));
};

export const listenPlayers = (callback) => {
  return onSnapshot(collection(db, 'players'), (snap) => {
    callback(snap.docs.map(d => ({ id: d.id, ...d.data() })));
  });
};

// --- ADMIN: ADD PLAYER (Using Secondary Auth to prevent Admin logout) ---
export const addPlayer = async (email, password, name) => {
  try {
    // 1. Check if email already exists in Firestore
    const q = query(collection(db, "players"), where("email", "==", email));
    const querySnapshot = await getDocs(q);
    if (!querySnapshot.empty) {
      throw new Error("A player with this email already exists!");
    }

    // 2. Create user in Firebase Auth using SECONDARY AUTH
    // This ensures the Admin's current session in 'auth' is not disturbed
    const userCredential = await createUserWithEmailAndPassword(secondaryAuth, email, password);
    const uid = userCredential.user.uid;

    // 3. Immediately sign out from the secondary instance
    await signOut(secondaryAuth);

    // 4. Create document in Firestore
    await setDoc(doc(db, "players", uid), {
      uid,
      name,
      email,
      isAdmin: false,
      hasWon: false,
      wonMonth: null,
      createdAt: new Date().toISOString()
    });

    return uid;
  } catch (error) {
    throw error;
  }
};

// --- ADMIN: DELETE PLAYER ---
export const deletePlayer = async (playerId) => {
  try {
    // Deletes the user profile from Firestore. 
    // Note: Deleting from Auth requires Admin SDK/Cloud Functions, 
    // but removing from Firestore blocks dashboard access.
    await deleteDoc(doc(db, "players", playerId));
  } catch (error) {
    throw error;
  }
};

// ─── AUCTION ────────────────────────────────────────────────────────────────
export const listenAuction = (callback) => {
  return onSnapshot(doc(db, 'auction', 'current'), (snap) => {
    callback(snap.exists() ? snap.data() : null);
  });
};

export const startAuction = async (settings) => {
  const { monthlyAmount, totalPlayers } = settings;
  const minBid = Math.floor(monthlyAmount * 0.1);
  const totalPool = monthlyAmount * totalPlayers;
  const endsAt = new Date(Date.now() + 15 * 60 * 1000).toISOString();

  const auctionData = {
    active: true,
    closed: false,
    month: new Date().toISOString().slice(0, 7),
    startedAt: new Date().toISOString(),
    endsAt,
    currentBid: minBid,
    currentBidder: null,
    currentBidderName: null,
    minBid,
    totalPool,
    monthlyAmount,
    totalPlayers,
    bids: [], 
    result: null
  };

  await setDoc(doc(db, 'auction', 'current'), auctionData);
};

export const placeBid = async (uid, playerName, amount) => {
  const auctionRef = doc(db, 'auction', 'current');
  const snap = await getDoc(auctionRef);
  if (!snap.exists()) throw new Error('No active auction found');

  const data = snap.data();
  if (!data.active || data.closed) throw new Error('Auction is closed');
  if (amount <= data.currentBid) throw new Error(`Bid must be more than ₹${data.currentBid}`);

  const bidEntry = { 
    uid, 
    playerName, 
    amount, 
    timestamp: new Date().toISOString() 
  };

  await updateDoc(auctionRef, {
    currentBid: amount,
    currentBidder: uid,
    currentBidderName: playerName,
    bids: [...(data.bids || []), bidEntry]
  });
};

export const closeAuction = async (auctionData) => {
  if (!auctionData) throw new Error("No auction data provided");

  const winningBid = auctionData.currentBid;
  const winnerReceives = auctionData.totalPool - winningBid;
  const perPlayerBonus = Math.floor(winningBid / auctionData.totalPlayers);

  const result = {
    month: auctionData.month,
    winnerId: auctionData.currentBidder,
    winnerName: auctionData.currentBidderName,
    winningBid,
    winnerReceives,
    perPlayerBonus,
    totalPool: auctionData.totalPool,
    closedAt: new Date().toISOString(),
    bids: auctionData.bids || []
  };

  const recordId = `${auctionData.month}-${Date.now()}`;
  await setDoc(doc(db, 'records', recordId), result);

  await updateDoc(doc(db, 'auction', 'current'), {
    active: false,
    closed: true,
    result
  });

  if (auctionData.currentBidder) {
    await updateDoc(doc(db, 'players', auctionData.currentBidder), {
      hasWon: true,
      wonMonth: auctionData.month
    });
  }

  return result;
};

// ─── RECORDS ────────────────────────────────────────────────────────────────
export const listenRecords = (callback) => {
  const q = query(collection(db, 'records'), orderBy('closedAt', 'desc'));
  return onSnapshot(q, (snap) => {
    callback(snap.docs.map(d => ({ id: d.id, ...d.data() })));
  });
};

// ─── RESET ──────────────────────────────────────────────────────────────────
export const resetAllWins = async () => {
  const players = await getPlayers();
  const promises = players.map(p => 
    updateDoc(doc(db, 'players', p.id), {
      hasWon: false,
      wonMonth: null
    })
  );
  await Promise.all(promises);
};
